import { describe, expect, it } from 'vitest';
import type { ProjectEvent } from '@agent-foundry/contracts';
import { mergeEvents } from './events.js';

function makeEvent(id: string, message: string): ProjectEvent {
  return {
    id,
    projectId: 'project-1',
    type: 'node.completed',
    createdAt: '2026-07-14T12:00:00.000Z',
    message,
    data: {},
  };
}

describe('mergeEvents', () => {
  it('merges incoming events into the existing list, sorted by id', () => {
    const existing = [makeEvent('evt-1', 'first'), makeEvent('evt-3', 'third')];
    const incoming = [makeEvent('evt-2', 'second')];

    const merged = mergeEvents(existing, incoming);

    expect(merged.map((event) => event.id)).toEqual(['evt-1', 'evt-2', 'evt-3']);
  });

  it('dedupes events that already exist by id', () => {
    const existing = [makeEvent('evt-1', 'first'), makeEvent('evt-2', 'second')];
    const incoming = [makeEvent('evt-2', 'second-again'), makeEvent('evt-3', 'third')];

    const merged = mergeEvents(existing, incoming);

    expect(merged.map((event) => event.id)).toEqual(['evt-1', 'evt-2', 'evt-3']);
    expect(merged.find((event) => event.id === 'evt-2')?.message).toBe('second');
  });

  it('returns the same array reference when there is nothing new to merge', () => {
    const existing = [makeEvent('evt-1', 'first'), makeEvent('evt-2', 'second')];

    const merged = mergeEvents(existing, [makeEvent('evt-1', 'first-again')]);

    expect(merged).toBe(existing);
  });
});
